from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a phrase
    import re
    from datetime import datetime

    def format_date(date_str: str) -> str:
        """Convert YYYY-MM-DD or similar to a readable format like 'January 20th, 1930'."""
        date_str = date_str.strip('"')
        # Try ISO format first
        try:
            dt = datetime.strptime(date_str, "%Y-%m-%d")
        except ValueError:
            # Try year-month format
            try:
                dt = datetime.strptime(date_str, "%Y-%m")
                return dt.strftime("%B %Y")
            except ValueError:
                return date_str  # fallback unchanged
        day = dt.day
        # ordinal suffix
        if 10 <= day % 100 <= 20:
            suffix = "th"
        else:
            suffix = {1: "st", 2: "nd", 3: "rd"}.get(day % 10, "th")
        return f"{dt.strftime('%B')} {day}{suffix}, {dt.year}"

    def phrase(subj: str, pred: str, obj: str) -> str:
        # Clean object
        obj = obj.strip('"')
        p = pred.lower()

        # Date handling
        if p in {"birthdate", "deathdate"}:
            return f"{subj} was born on {format_date(obj)}" if p == "birthdate" else f"{subj} died on {format_date(obj)}"
        if p in {"dateofretirement"}:
            return f"{subj} retired in {obj}"
        if p in {"birthplace", "deathplace"}:
            return f"{subj} was born in {obj}" if p == "birthplace" else f"{subj} died in {obj}"
        if p == "nationality":
            return f"{subj} was a {obj} citizen"
        if p == "occupation":
            return f"{subj} was a {obj}"
        if p == "status":
            # Adjust phrasing for common statuses
            low = obj.lower()
            if low in {"retired", "retiree"}:
                return f"{subj} is a retired"
            return f"{subj} is {low}"
        if p == "selectedbynasa":
            return f"{subj} was selected by NASA in {obj}"
        if p == "mission":
            return f"{subj} flew on {obj}"
        if p == "timeinspace":
            # Convert minutes to hours if large
            try:
                mins = float(re.sub(r"[^0-9.]", "", obj))
                hours = mins / 60
                if hours >= 1:
                    return f"{subj} spent {hours:.1f} hours in space"
            except Exception:
                pass
            return f"{subj} spent {obj} minutes in space"
        if p == "title":
            return f"{subj} held the title of {obj}"
        if p == "award":
            return f"{subj} received the {obj}"
        if p == "awards":
            return f"{subj} received {obj} awards"
        if p == "ribbonaward":
            return f"{subj} was awarded the {obj}"
        if p == "operator":
            return f"{subj} was operated by {obj}"
        if p == "commander":
            return f"{obj} was the commander of {subj}"
        if p == "backuppilot":
            return f"{subj}'s backup pilot was {obj}"
        if p == "crewmembers":
            return f"{obj} was a crew member of {subj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"{subj} served as Chief of the Astronaut Office in {obj}"
        if p == "bird":
            # Assume obj is the bird name
            bird_name = obj.lower()
            return f"The {bird_name} is the state bird of {subj}"
        if p == "alternativename":
            return f"{subj} is also known as {obj}"
        if p == "representative":
            return f"{obj} represented {subj}"
        if p == "fossil":
            return f"{subj} is known for the fossil {obj}"
        if p == "senators":
            return f"{subj} is represented by Senator {obj}"
        if p == "part":
            return f"{subj} is part of {obj}"
        if p == "ispartof":
            return f"{subj} is part of {obj}"
        if p == "leader":
            return f"The leader of {subj} is {obj}"
        if p == "affiliation":
            return f"{subj} is affiliated with {obj}"
        if p == "competein":
            return f"{subj} competes in the {obj}"
        if p == "president":
            return f"The president of {subj} is {obj}"
        if p == "deathplace":
            return f"{subj} died in {obj}"
        if p == "gemstone":
            return f"{subj}'s gemstone is {obj}"
        if p == "mascot":
            return f"The mascot of {subj} is {obj}"
        if p == "cosparid":
            return f"The COSPAR ID of {subj} is {obj}"
        if p == "utcoffset":
            return f"{subj} has a UTC offset of {obj}"
        # Fallback
        return f"{subj} {pred} {obj}"

    # Build phrases in the order of input triples and combine into a single sentence
    parts = [phrase(t.subject, t.predicate, t.object) for t in triples]

    # Join with commas; add 'and' before the last part if more than one
    if not parts:
        return ""
    if len(parts) == 1:
        sentence = parts[0]
    else:
        sentence = ", ".join(parts[:-1]) + ", and " + parts[-1]

    return sentence + "."

# EVOLVE-BLOCK-END
